async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    await browser.navigateTo('https://www.instacart.com/');
    await browser.awaitPageLoad();

    if (params.storeName) {
        const store = await browser.extractComponent<{ name: string; linkSelector?: string }>({
            typeName: 'StoreInfo',
            schema: '{ name: string; subtitle?: string; linkSelector?: string; }'
        }, params.storeName);
        if (store && store.linkSelector) {
            await browser.clickAndWait(store.linkSelector);
        }
    }

    const listsNav = await browser.extractComponent<{ linkSelector: string }>({
        typeName: 'ListsNavigationLink',
        schema: '{ linkSelector: string; }'
    });
    if (!listsNav || !listsNav.linkSelector) {
        throw new Error('Could not find lists navigation link');
    }
    await browser.clickAndWait(listsNav.linkSelector);

    const list = await browser.extractComponent<{ name: string; detailsLinkSelector: string }>({
        typeName: 'ListInfo',
        schema: '{ name: string; detailsLinkSelector: string; }'
    }, params.listName);
    if (!list || !list.detailsLinkSelector) {
        throw new Error('Could not find list: ' + params.listName);
    }
    await browser.clickAndWait(list.detailsLinkSelector);

    const details = await browser.extractComponent<{ name: string; products?: { name: string; price: string; availability?: string; addToCartButtonSelector?: string }[] }>({
        typeName: 'ListDetailsInfo',
        schema: '{ name: string; storeName?: string; products?: { name: string; price: string; availability?: string; addToCartButtonSelector?: string; }[]; }'
    });
    if (!details || !details.products || details.products.length === 0) {
        return { success: false, error: 'No products found in list ' + params.listName };
    }

    let added = 0;
    const unavailable: string[] = [];
    for (const product of details.products) {
        if (product.availability === 'Out of stock') {
            unavailable.push(product.name);
        } else if (product.addToCartButtonSelector) {
            await browser.click(product.addToCartButtonSelector);
            await browser.awaitPageInteraction();
            added++;
        }
    }

    let message = 'Added ' + added + ' items from "' + params.listName + '" to cart';
    if (unavailable.length > 0) {
        message += '. Unavailable: ' + unavailable.join(', ');
    }
    return { success: true, message };
}
